Consider the following JavaScript code that implements a part of a Minesweeper game:

```javascript
const mines = [];
const untouched = [];
let playable = true;

function newGame() {
  // reset state
  while (untouched.length) untouched.pop();
  while (mines.length) mines.pop();
  playable = true;

  // build 400 tiles, randomly assign mines
  for (let i = 0; i < 400; i++) {
    const tile = document.createElement('div');
    tile.id = `tile_${i}`;
    if (Math.random() < 0.10) {
      mines.push(tile.id);
    }
    untouched.push(tile.id);
    const handler = function() { touchTile(tile.id); };
    tile.addEventListener('click', handler);
    document.querySelector('.board').appendChild(tile);
  }
}

function touchTile(id) {
  if (!playable) return;
  const tile = document.getElementById(id);
  if (!untouched.includes(id)) return;
  if (mines.includes(id)) {
    tile.className = 'bomb';
    tile.textContent = '*';
    playable = false;
    return;
  }
  tile.className = 'clear';
  untouched.splice(untouched.indexOf(id), 1);
  // ... further logic omitted
